// Preparar fechas, UUID y ambas queries
var now = new Date();
var y = now.getFullYear();
var m = String(now.getMonth() + 1).padStart(2, '0');
var lastDay = new Date(y, now.getMonth() + 1, 0).getDate();

var startDate = y + m + '01';
var endDate = y + m + String(lastDay).padStart(2, '0');
var sync_uuid = (
  Date.now().toString(36).toUpperCase().slice(-4) +
  Math.random().toString(36).substring(2, 10).toUpperCase()
);
var timestamp = new Date().toISOString();
var periodo = startDate + '-' + endDate;

// Rama 1: SumasSaldos (agregada por cuenta, mes actual)
var ssQuery = `
                SELECT
  V_EZI_CUENTAS.CODIGO,
  V_EZI_CUENTAS.DESCRIPCION AS CUENTA,
  V_EZI_CUENTAS.CRubro,
  V_EZI_CUENTAS.NRubro,
  CASE
    WHEN V_TRCONTABLE_.UNIDADOPERATIVA_ID = '89C235FC-3F01-11D5-86AD-0080AD403F5F' THEN 'DTA'
    WHEN V_TRCONTABLE_.UNIDADOPERATIVA_ID = 'EA17FA63-D4C8-4C97-951C-D74EA44B8917' THEN 'BLC'
    WHEN V_TRCONTABLE_.UNIDADOPERATIVA_ID = 'E6D4EF31-1D97-484D-838F-C16F7DB2FD31' THEN 'AALC'
    WHEN V_TRCONTABLE_.UNIDADOPERATIVA_ID = '6A240BE0-160C-4F6A-8018-29DCCA57032E' THEN 'SAS'
    WHEN V_TRCONTABLE_.UNIDADOPERATIVA_ID = '3E81DE7D-7813-492E-B12C-1ECD28401637' THEN '9-INGENIO'
    ELSE '' END AS UNIDAD_NEGOCIO,
  SUM(V_VALOR_.IMPORTE) AS DEBE_PERIODO,
  SUM(V_VALOR_1.IMPORTE) AS HABER_PERIODO
FROM V_TRCONTABLE_
INNER JOIN V_ITEMCONTABLE_ ON V_TRCONTABLE_.ITEMSTRANSACCION_ID = V_ITEMCONTABLE_.BO_PLACE_ID
INNER JOIN V_VALOR_ ON V_ITEMCONTABLE_.DEBE_ID = V_VALOR_.ID
INNER JOIN V_VALOR_ AS V_VALOR_1 ON V_ITEMCONTABLE_.HABER_ID = V_VALOR_1.ID
INNER JOIN V_EZI_CUENTAS ON V_ITEMCONTABLE_.REFERENCIA_ID = V_EZI_CUENTAS.ID
WHERE SUBSTRING(V_TRCONTABLE_.FECHAAPLICACION,1,8) >= '${startDate}'
  AND SUBSTRING(V_TRCONTABLE_.FECHAAPLICACION,1,8) <= '${endDate}'
  AND V_EZI_CUENTAS.CODIGO BETWEEN '0' AND '9'
  AND V_TRCONTABLE_.ESTADO = 'C'
GROUP BY V_EZI_CUENTAS.CODIGO, V_EZI_CUENTAS.DESCRIPCION, V_EZI_CUENTAS.CRubro, V_EZI_CUENTAS.NRubro, CASE
    WHEN V_TRCONTABLE_.UNIDADOPERATIVA_ID = '89C235FC-3F01-11D5-86AD-0080AD403F5F' THEN 'DTA'
    WHEN V_TRCONTABLE_.UNIDADOPERATIVA_ID = 'EA17FA63-D4C8-4C97-951C-D74EA44B8917' THEN 'BLC'
    WHEN V_TRCONTABLE_.UNIDADOPERATIVA_ID = 'E6D4EF31-1D97-484D-838F-C16F7DB2FD31' THEN 'AALC'
    WHEN V_TRCONTABLE_.UNIDADOPERATIVA_ID = '6A240BE0-160C-4F6A-8018-29DCCA57032E' THEN 'SAS'
    WHEN V_TRCONTABLE_.UNIDADOPERATIVA_ID = '3E81DE7D-7813-492E-B12C-1ECD28401637' THEN '9-INGENIO'
    ELSE '' END AS UNIDAD_NEGOCIO
ORDER BY V_EZI_CUENTAS.CODIGO
`;
// ` `;

// Rama 2: Movimientos (ultimos 30 dias)
var movQuery = `SELECT
  V_EZI_CUENTAS.CODIGO,
  V_EZI_CUENTAS.DESCRIPCION AS CUENTA,
  SUBSTRING(V_TRCONTABLE_.FECHAAPLICACION,1,8) AS FECHA,
  CASE
    WHEN V_TRCONTABLE_.UNIDADOPERATIVA_ID = '89C235FC-3F01-11D5-86AD-0080AD403F5F' THEN 'DTA'
    WHEN V_TRCONTABLE_.UNIDADOPERATIVA_ID = 'EA17FA63-D4C8-4C97-951C-D74EA44B8917' THEN 'BLC'
    WHEN V_TRCONTABLE_.UNIDADOPERATIVA_ID = 'E6D4EF31-1D97-484D-838F-C16F7DB2FD31' THEN 'AALC'
    WHEN V_TRCONTABLE_.UNIDADOPERATIVA_ID = '6A240BE0-160C-4F6A-8018-29DCCA57032E' THEN 'SAS'
    WHEN V_TRCONTABLE_.UNIDADOPERATIVA_ID = '3E81DE7D-7813-492E-B12C-1ECD28401637' THEN '9-INGENIO'
    ELSE '' END AS UNIDAD_NEGOCIO,
  V_TRCONTABLE_.NUMERODOCUMENTO AS ASIENTO,
  V_TRCONTABLE_.DETALLE AS DESCRIPCION,
  V_TRCONTABLE_.NOMBREDESTINATARIO AS PROVEEDOR,
  V_ITEMCONTABLE_.DESCRIPCION AS ITEM,
  V_VALOR_.IMPORTE AS DEBE,
  V_VALOR_1.IMPORTE AS HABER,
  V_VALOR_.IMPORTE - V_VALOR_1.IMPORTE AS SALDO
FROM V_TRCONTABLE_
INNER JOIN V_ITEMCONTABLE_ ON V_TRCONTABLE_.ITEMSTRANSACCION_ID = V_ITEMCONTABLE_.BO_PLACE_ID
INNER JOIN V_VALOR_ ON V_ITEMCONTABLE_.DEBE_ID = V_VALOR_.ID
INNER JOIN V_VALOR_ AS V_VALOR_1 ON V_ITEMCONTABLE_.HABER_ID = V_VALOR_1.ID
INNER JOIN V_EZI_CUENTAS ON V_ITEMCONTABLE_.REFERENCIA_ID = V_EZI_CUENTAS.ID
WHERE V_TRCONTABLE_.ESTADO = 'C'
  AND V_EZI_CUENTAS.CODIGO BETWEEN '0' AND '9'
  AND CONVERT(DATE, SUBSTRING(V_TRCONTABLE_.FECHAAPLICACION,1,8), 112) >= CONVERT(DATE, DATEADD(DAY, -365, GETDATE()), 112)
ORDER BY V_TRCONTABLE_.FECHAAPLICACION DESC; `;

node.warn('[Sync-v3] Iniciando sync ' + sync_uuid + ' periodo ' + periodo);

// msg1 → wire[0] = SumasSaldos
msg.payload = ssQuery;
msg.startDate = startDate;
msg.endDate = endDate;
msg.sync_uuid = sync_uuid;
msg.timestamp = timestamp;
msg.periodo = periodo;

// msg2 → wire[1] = Movimientos
var msg2 = JSON.parse(JSON.stringify(msg));
msg2.payload = movQuery;

return [msg, msg2];

var rows = msg.payload;
var sync_uuid = msg.sync_uuid || 'N/A';
var periodo = msg.periodo || '';
var timestamp = msg.timestamp || new Date().toISOString();

msg._branch = 'SumasSaldos';
msg._syncInfo = { sync_uuid: sync_uuid, periodo: periodo, timestamp: timestamp, branch: 'SumasSaldos' };

if (!rows || !Array.isArray(rows) || rows.length === 0) {
  node.warn('[Sync-v3] SumasSaldos: sin datos del MSSQL');
  msg._syncInfo.empty = true;
  msg._newRows = [];
  return msg;
}

var data = [];
for (var i = 0; i < rows.length; i++) {
  var r = rows[i];
  var debe = parseFloat(r.DEBE_PERIODO) || 0;
  var haber = parseFloat(r.HABER_PERIODO) || 0;
  data.push([
    r.CODIGO || '',
    r.CUENTA || '',
    r.NRubro || '',
    debe,
    haber,
    debe - haber,
    periodo,
    timestamp,
    r.UNIDAD_NEGOCIO || ''
  ]);
}

msg._newRows = data;
node.warn('[Sync-v3] SumasSaldos: ' + data.length + ' filas MSSQL');
return msg;

var newRows = msg._newRows || [];
var existingRows = msg.payload || [];
var info = msg._syncInfo || {};

if (info.empty || newRows.length === 0) {
  msg.payload = null;
  return msg;
}

// Set de CODIGO existentes
var existingKeys = new Set();
if (Array.isArray(existingRows)) {
  for (var i = 0; i < existingRows.length; i++) {
    var row = existingRows[i];
    if (Array.isArray(row) && row.length > 0) {
      existingKeys.add(String(row[0] || '').trim() + '|' + String(row[6] || '').trim());
    }
  }
}

// Filtrar solo nuevos
var filtered = [];
for (var j = 0; j < newRows.length; j++) {
  var key = String(newRows[j][0] || '').trim() + '|' + String(newRows[j][6] || '').trim();
  if (!existingKeys.has(key)) filtered.push(newRows[j]);
}

var skipped = newRows.length - filtered.length;
node.warn('[Sync-v3] SumasSaldos dedup: ' + newRows.length + ' MSSQL, ' + skipped + ' ya existen, ' + filtered.length + ' nuevos');

msg._syncInfo.skipped = skipped;
msg._syncInfo.rowCount = filtered.length;

if (filtered.length === 0) {
  msg._syncInfo.empty = true;
  msg.payload = null;
} else {
  msg.payload = filtered;
}
return msg;

var info = msg._syncInfo || {};
if (info.empty) {
  node.warn('[Sync-v3] SumasSaldos: sin filas nuevas');
} else {
  var range = (msg.payload && msg.payload.updates) ? msg.payload.updates.updatedRange : '';
  node.warn('[Sync-v3] ✅ SumasSaldos: ' + (info.rowCount || 0) + ' filas → ' + range);
}
return msg;

var rows = msg.payload;
var sync_uuid = msg.sync_uuid || 'N/A';

msg._branch = 'Movimientos';
msg._syncInfo = { sync_uuid: sync_uuid, branch: 'Movimientos' };

if (!rows || !Array.isArray(rows) || rows.length === 0) {
  node.warn('[Sync-v3] Movimientos: sin datos del MSSQL');
  msg._syncInfo.empty = true;
  msg._newRows = [];
  return msg;
}

var data = [];
for (var i = 0; i < rows.length; i++) {
  var r = rows[i];
  data.push([
    r.CODIGO || '',
    r.CUENTA || '',
    r.FECHA || '',
    r.ASIENTO || '',
    r.DESCRIPCION || '',
    r.PROVEEDOR || '',
    r.ITEM || '',
    parseFloat(r.DEBE) || 0,
    parseFloat(r.HABER) || 0,
    parseFloat(r.SALDO) || 0,
    r.UNIDAD_NEGOCIO || ''
  ]);
}

msg._newRows = data;
node.warn('[Sync-v3] Movimientos: ' + data.length + ' filas MSSQL');
return msg;

var newRows = msg._newRows || [];
var existingRows = msg.payload || [];
var info = msg._syncInfo || {};

if (info.empty || newRows.length === 0) {
  msg.payload = null;
  return msg;
}

// Set de CODIGO|ASIENTO existentes
var existingKeys = new Set();
if (Array.isArray(existingRows)) {
  for (var i = 0; i < existingRows.length; i++) {
    var row = existingRows[i];
    if (Array.isArray(row) && row.length >= 4) {
      existingKeys.add(String(row[0] || '').trim() + '|' + String(row[3] || '').trim());
    }
  }
}

// Filtrar solo nuevos
var filtered = [];
for (var j = 0; j < newRows.length; j++) {
  var key = String(newRows[j][0] || '').trim() + '|' + String(newRows[j][3] || '').trim();
  if (!existingKeys.has(key)) filtered.push(newRows[j]);
}

var skipped = newRows.length - filtered.length;
node.warn('[Sync-v3] Movimientos dedup: ' + newRows.length + ' MSSQL, ' + skipped + ' ya existen, ' + filtered.length + ' nuevos');

msg._syncInfo.skipped = skipped;
msg._syncInfo.rowCount = filtered.length;

if (filtered.length === 0) {
  msg._syncInfo.empty = true;
  msg.payload = null;
} else {
  msg.payload = filtered;
}
return msg;

var info = msg._syncInfo || {};
if (info.empty) {
  node.warn('[Sync-v3] Movimientos: sin filas nuevas');
} else {
  var range = (msg.payload && msg.payload.updates) ? msg.payload.updates.updatedRange : '';
  node.warn('[Sync-v3] ✅ Movimientos: ' + (info.rowCount || 0) + ' filas → ' + range);
}
return msg;
